var existing = _.get(data, 'formatter._originalConfig'); 
if (existing === undefined || existing === null) { 
  value = _.cloneDeep(_.get(data, 'formatter.config')) || {};
} else { 
  value = existing; 
}

data.custom:
const registry = Citeck.FormattersRegistry;
if (registry) {
  const formatters = registry.getAllFormatters();
  values = formatters.map((formatter) => ({
    label: `journals.formatter.${formatter.getType()}.name`, 
    value: formatter.getType(),
  }));
}

components.calculateValue:
value = _.get(data, 'formatter._originalConfig.colors');
if (value === undefined){
  var oldFormatValueObj = _.get(data, 'formatter._originalConfig.color');
  if (oldFormatValueObj !== undefined){
    var oldFormatValues = { ...oldFormatValueObj };
	  try {
      var values = Object.values(oldFormatValues);
      if (values.length > 0){
        for (const [key, style] of Object.entries(oldFormatValues)) {          
            oldFormatValues[key] = { backgroundColor: style};
        }
        _.set(data, 'formatter._originalConfig.colors', oldFormatValues);
        value = oldFormatValues;        
      }
	  } catch (e) {
		  console.error(e);
	  }
  } else {
    value = {};
  }
}

var type = _.get(data, 'formatter.type');
if (type === 'script') {
    value = {};
    var fn = _.get(data, 'formatter._scriptFn');
    if (!fn) fn = _.get(data, 'formatter._originalConfig.fn');
    if (fn) value.fn = fn;
    var vars = _.get(data, 'formatter._scriptVars');
    if (!vars || Object.keys(vars).length === 0) vars = _.get(data, 'formatter._originalConfig.vars');
    if (vars && Object.keys(vars).length > 0) value.vars = vars;
} else if (type === 'colored') {
    value = {};
    var defColor = _.get(data, 'formatter._coloredDefaultColor');
    if (!defColor) defColor = _.get(data, 'formatter._originalConfig.defaultColor');
    if (defColor) value.defaultColor = defColor;
    var showPtr = _.get(data, 'formatter._coloredShowPointer');
    if (showPtr === undefined || showPtr === null) showPtr = _.get(data, 'formatter._originalConfig.showPointer');
    if (showPtr === true) value.showPointer = true;
    var colorMap = _.get(data, 'formatter._coloredColorMap');
    if (!colorMap || Object.keys(colorMap).length === 0) colorMap = _.get(data, 'formatter._originalConfig.colors');
    if (colorMap && Object.keys(colorMap).length > 0) value.colors = colorMap;
    var fn = _.get(data, 'formatter._coloredFn');
    if (!fn) fn = _.get(data, 'formatter._originalConfig.fn');
    if (fn) value.fn = fn;
} else {
    value = _.get(data, 'formatter._configOther') || _.get(data, 'formatter._originalConfig') || {};
}
